INSERT INTO license_plans (name,slug,description,status,max_exams,max_participants_month,max_admin_users,result_retention_months,features_json) VALUES ('Plano Flex','plano-flex','Para demandas pontuais ou sazonais de testes e avaliações, com créditos sem prazo de validade.','active',NULL,NULL,5,NULL,'["exams","excel_import","branding","participants","results","export_results","priority_support","prepaid_credits"]') ON DUPLICATE KEY UPDATE name=VALUES(name),description=VALUES(description),status=VALUES(status),max_exams=VALUES(max_exams),max_participants_month=VALUES(max_participants_month),max_admin_users=VALUES(max_admin_users),result_retention_months=VALUES(result_retention_months),features_json=VALUES(features_json);
